package io.github.njw3995.fabricmmo.core.teleport;

import java.time.Clock;import java.time.Duration;import java.time.Instant;import java.util.HashMap;import java.util.Map;import java.util.Objects;import java.util.Optional;import java.util.UUID;
public final class PartyTeleportRequests { private final Clock clock;private final Duration lifetime;private final Map<UUID,Map<UUID,Instant>> requests=new HashMap<>();public PartyTeleportRequests(Clock clock,Duration lifetime){this.clock=Objects.requireNonNull(clock,"clock");this.lifetime=Objects.requireNonNull(lifetime,"lifetime");}public synchronized void request(UUID requester,UUID target){evict();requests.computeIfAbsent(target,k->new HashMap<>()).put(requester,clock.instant().plus(lifetime));}public synchronized Optional<UUID> accept(UUID target,Optional<UUID> requester){evict();Map<UUID,Instant> pending=requests.get(target);if(pending==null||pending.isEmpty())return Optional.empty();UUID selected=requester.filter(pending::containsKey).orElseGet(()->pending.entrySet().stream().max(Map.Entry.comparingByValue()).map(Map.Entry::getKey).orElse(null));if(selected!=null)pending.remove(selected);if(pending.isEmpty())requests.remove(target);return Optional.ofNullable(selected);}public synchronized int pending(UUID target){evict();return requests.getOrDefault(target,Map.of()).size();}public synchronized void remove(UUID id){requests.remove(id);requests.values().forEach(m->m.remove(id));}private void evict(){Instant now=clock.instant();requests.values().forEach(m->m.entrySet().removeIf(e->!e.getValue().isAfter(now)));requests.entrySet().removeIf(e->e.getValue().isEmpty());} }
